import{_ as a,o as n,c as l,a4 as i}from"./chunks/framework._in6GHBg.js";const d=JSON.parse('{"title":"三角函数详解","description":"","frontmatter":{},"headers":[],"relativePath":"math/Math-Learn-Detail-002-三角函数详解-V1.0-20260405.md","filePath":"math/Math-Learn-Detail-002-三角函数详解-V1.0-20260405.md"}'),t={name:"math/Math-Learn-Detail-002-三角函数详解-V1.0-20260405.md"};function o(e,s,r,p,c,h){return n(),l("div",null,[...s[0]||(s[0]=[i(`<h1 id="三角函数详解" tabindex="-1">三角函数详解 <a class="header-anchor" href="#三角函数详解" aria-label="Permalink to &quot;三角函数详解&quot;">​</a></h1><p><strong>从&quot;边角关系&quot;到&quot;周期现象的描述工具&quot;</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>学完本章，你将：</p><ol><li>理解三角函数是描述周期现象的工具</li><li>掌握三角函数的图像与性质</li><li>熟练运用三角恒等变换和解三角形</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>三角函数</span></span>
<span class="line"><span>├── 三角函数基础</span></span>
<span class="line"><span>│   ├── 任意角与弧度制</span></span>
<span class="line"><span>│   ├── 三角函数定义（单位圆）</span></span>
<span class="line"><span>│   ├── 同角三角函数关系</span></span>
<span class="line"><span>│   └── 诱导公式</span></span>
<span class="line"><span>├── 三角函数图像与性质</span></span>
<span class="line"><span>│   ├── y=sinx, y=cosx, y=tanx图像</span></span>
<span class="line"><span>│   ├── 周期性、单调性、最值</span></span>
<span class="line"><span>│   └── 图像变换（平移/伸缩）</span></span>
<span class="line"><span>├── 三角恒等变换</span></span>
<span class="line"><span>│   ├── 两角和差公式 ⭐</span></span>
<span class="line"><span>│   ├── 二倍角公式 ⭐</span></span>
<span class="line"><span>│   ├── 辅助角公式</span></span>
<span class="line"><span>│   └── 恒等变换综合 ⭐</span></span>
<span class="line"><span>└── 解三角形</span></span>
<span class="line"><span>    ├── 正弦定理 ⭐</span></span>
<span class="line"><span>    ├── 余弦定理 ⭐</span></span>
<span class="line"><span>    └── 解三角形综合 ⭐</span></span></code></pre></div><h3 id="前后联系" tabindex="-1">前后联系 <a class="header-anchor" href="#前后联系" aria-label="Permalink to &quot;前后联系&quot;">​</a></h3><ul><li><strong>前置知识</strong>：函数概念、初中三角函数（锐角）</li><li><strong>后续应用</strong>：物理（振动与波）、导数（三角函数求导）</li><li><strong>跨学科联系</strong>：物理（简谐振动、交流电）、工程（信号处理）</li></ul><hr><h2 id="二、概念定义" tabindex="-1">二、概念定义 <a class="header-anchor" href="#二、概念定义" aria-label="Permalink to &quot;二、概念定义&quot;">​</a></h2><h3 id="_2-1-任意角与弧度制" tabindex="-1">2.1 任意角与弧度制 <a class="header-anchor" href="#_2-1-任意角与弧度制" aria-label="Permalink to &quot;2.1 任意角与弧度制&quot;">​</a></h3><p><strong>任意角</strong>：</p><ul><li>角可以推广到任意大小（正角、负角、零角）</li><li>终边相同的角相差360°的整数倍</li></ul><p><strong>弧度制</strong>：</p><ul><li>1弧度 = 弧长等于半径时圆心角的大小</li><li><strong>换算公式</strong>：π rad = 180°</li><li><strong>常用换算</strong>： <ul><li>30° = π/6</li><li>45° = π/4</li><li>60° = π/3</li><li>90° = π/2</li></ul></li></ul><p><strong>为什么要用弧度制？</strong></p><ul><li>微积分中，弧度制下 (sinx)&#39; = cosx（简洁）</li><li>角度制下求导会有系数</li></ul><hr><h3 id="_2-2-三角函数定义-单位圆" tabindex="-1">2.2 三角函数定义（单位圆） <a class="header-anchor" href="#_2-2-三角函数定义-单位圆" aria-label="Permalink to &quot;2.2 三角函数定义（单位圆）&quot;">​</a></h3><p><strong>定义</strong>：角α的终边与单位圆交于点P(x, y)，则：</p><ul><li>sinα = y（纵坐标）</li><li>cosα = x（横坐标）</li><li>tanα = y/x = sinα/cosα</li></ul><p><strong>理解</strong>：</p><ul><li>单位圆上的点P(x,y)，x=cosα, y=sinα</li><li>三角函数的值就是坐标</li></ul><hr><h3 id="_2-3-同角三角函数关系" tabindex="-1">2.3 同角三角函数关系 <a class="header-anchor" href="#_2-3-同角三角函数关系" aria-label="Permalink to &quot;2.3 同角三角函数关系&quot;">​</a></h3><p><strong>基本关系</strong>：</p><ol><li><strong>平方关系</strong>：sin²α + cos²α = 1</li><li><strong>商数关系</strong>：tanα = sinα/cosα</li></ol><p><strong>应用</strong>：</p><ul><li>已知sin求cos（注意正负号由象限确定）</li><li>弦化切、切化弦</li></ul><hr><h3 id="_2-4-诱导公式" tabindex="-1">2.4 诱导公式 <a class="header-anchor" href="#_2-4-诱导公式" aria-label="Permalink to &quot;2.4 诱导公式&quot;">​</a></h3><p><strong>口诀</strong>：<strong>奇变偶不变，符号看象限</strong></p><p><strong>解释</strong>：</p><ul><li><strong>奇偶</strong>：指π/2的倍数 <ul><li>奇数倍（π/2, 3π/2...）：函数名改变（sin↔cos, tan↔cot）</li><li>偶数倍（π, 2π...）：函数名不变</li></ul></li><li><strong>符号</strong>：把α看成锐角，看原函数在相应象限的符号</li></ul><p><strong>常用诱导公式</strong>：</p><ul><li>sin(π+α) = -sinα</li><li>cos(π+α) = -cosα</li><li>sin(-α) = -sinα（奇函数）</li><li>cos(-α) = cosα（偶函数）</li><li>sin(π/2-α) = cosα</li><li>cos(π/2-α) = sinα</li></ul><hr><h3 id="_2-5-三角函数图像与性质-⭐" tabindex="-1">2.5 三角函数图像与性质 ⭐ <a class="header-anchor" href="#_2-5-三角函数图像与性质-⭐" aria-label="Permalink to &quot;2.5 三角函数图像与性质 ⭐&quot;">​</a></h3><p><strong>y = sinx</strong>：</p><ul><li>周期：2π</li><li>振幅：1</li><li>单调增：[−π/2+2kπ, π/2+2kπ]</li><li>单调减：[π/2+2kπ, 3π/2+2kπ]</li><li>最大值1（x=π/2+2kπ），最小值-1（x=−π/2+2kπ）</li></ul><p><strong>y = cosx</strong>：</p><ul><li>周期：2π</li><li>由sinx向左平移π/2得到：cosx = sin(x+π/2)</li></ul><p><strong>y = tanx</strong>：</p><ul><li>周期：π（注意是π不是2π）</li><li>定义域：x ≠ π/2+kπ</li><li>在每个周期内单调递增</li></ul><p><strong>一般形式</strong> y = Asin(ωx+φ) + B：</p><ul><li><strong>A</strong>：振幅（最大值-最小值）/2</li><li><strong>ω</strong>：角频率，周期T = 2π/|ω|</li><li><strong>φ</strong>：初相（决定起点位置）</li><li><strong>B</strong>：上下平移（中线位置）</li></ul><hr><h3 id="_2-6-三角恒等变换-⭐" tabindex="-1">2.6 三角恒等变换 ⭐ <a class="header-anchor" href="#_2-6-三角恒等变换-⭐" aria-label="Permalink to &quot;2.6 三角恒等变换 ⭐&quot;">​</a></h3><p><strong>两角和差公式</strong>：</p><ul><li>sin(α±β) = sinαcosβ ± cosαsinβ</li><li>cos(α±β) = cosαcosβ ∓ sinαsinβ</li><li>tan(α±β) = (tanα±tanβ)/(1∓tanαtanβ)</li></ul><p><strong>二倍角公式</strong>：</p><ul><li>sin2α = 2sinαcosα</li><li>cos2α = cos²α - sin²α = 2cos²α - 1 = 1 - 2sin²α</li><li>tan2α = 2tanα/(1-tan²α)</li></ul><p><strong>降幂公式</strong>（由二倍角变形）：</p><ul><li>sin²α = (1-cos2α)/2</li><li>cos²α = (1+cos2α)/2</li></ul><p><strong>辅助角公式</strong>：</p><ul><li>asinx + bcosx = √(a²+b²) · sin(x+φ)</li><li>其中tanφ = b/a</li></ul><hr><h3 id="_2-7-解三角形-⭐" tabindex="-1">2.7 解三角形 ⭐ <a class="header-anchor" href="#_2-7-解三角形-⭐" aria-label="Permalink to &quot;2.7 解三角形 ⭐&quot;">​</a></h3><p><strong>正弦定理</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>a/sinA = b/sinB = c/sinC = 2R</span></span></code></pre></div><p>（R为外接圆半径）</p><p><strong>应用</strong>：已知两角一边、两边一对角</p><p><strong>余弦定理</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>a² = b² + c² - 2bc·cosA</span></span>
<span class="line"><span>b² = a² + c² - 2ac·cosB</span></span>
<span class="line"><span>c² = a² + b² - 2ab·cosC</span></span></code></pre></div><p><strong>变形</strong>（求角）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cosA = (b²+c²-a²)/(2bc)</span></span></code></pre></div><p><strong>应用</strong>：已知两边夹角、三边</p><p><strong>三角形面积公式</strong>：</p><ul><li>S = (1/2)ab·sinC = (1/2)bc·sinA = (1/2)ac·sinB</li></ul><hr><h2 id="三、典型例题" tabindex="-1">三、典型例题 <a class="header-anchor" href="#三、典型例题" aria-label="Permalink to &quot;三、典型例题&quot;">​</a></h2><h3 id="例题1-诱导公式化简" tabindex="-1">例题1：诱导公式化简 <a class="header-anchor" href="#例题1-诱导公式化简" aria-label="Permalink to &quot;例题1：诱导公式化简&quot;">​</a></h3><p><strong>题目</strong>：化简 sin(π+α)·cos(π-α)·tan(-α)</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sin(π+α) = -sinα</span></span>
<span class="line"><span>cos(π-α) = -cosα</span></span>
<span class="line"><span>tan(-α) = -tanα = -sinα/cosα</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原式 = (-sinα)·(-cosα)·(-sinα/cosα)</span></span>
<span class="line"><span>     = -sin²α</span></span></code></pre></div><p><strong>关键点</strong>：</p><ul><li>奇变偶不变：π是π/2的2倍（偶），函数名不变</li><li>符号看象限：π+α在第三象限，sin为负</li></ul><hr><h3 id="例题2-三角函数图像变换" tabindex="-1">例题2：三角函数图像变换 <a class="header-anchor" href="#例题2-三角函数图像变换" aria-label="Permalink to &quot;例题2：三角函数图像变换&quot;">​</a></h3><p><strong>题目</strong>：要得到y = sin(2x-π/3)的图像，只需将y = sin2x的图像如何平移？</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>y = sin(2x-π/3) = sin[2(x-π/6)]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ 向右平移π/6个单位</span></span></code></pre></div><p><strong>注意</strong>：</p><ul><li>不是平移π/3！</li><li>提取系数2：2x-π/3 = 2(x-π/6)</li><li>平移量 = φ/ω = (π/3)/2 = π/6</li></ul><hr><h3 id="例题3-解三角形" tabindex="-1">例题3：解三角形 <a class="header-anchor" href="#例题3-解三角形" aria-label="Permalink to &quot;例题3：解三角形&quot;">​</a></h3><p><strong>题目</strong>：在△ABC中，a=2, b=3, C=60°，求c和面积。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>求c（余弦定理）：</span></span>
<span class="line"><span>c² = a² + b² - 2ab·cosC</span></span>
<span class="line"><span>   = 4 + 9 - 2×2×3×(1/2)</span></span>
<span class="line"><span>   = 13 - 6 = 7</span></span>
<span class="line"><span>∴ c = √7</span></span>
<span class="line"><span></span></span>
<span class="line"><span>面积：</span></span>
<span class="line"><span>S = (1/2)ab·sinC</span></span>
<span class="line"><span>  = (1/2)×2×3×(√3/2)</span></span>
<span class="line"><span>  = 3√3/2</span></span></code></pre></div><hr><h2 id="四、配套练习" tabindex="-1">四、配套练习 <a class="header-anchor" href="#四、配套练习" aria-label="Permalink to &quot;四、配套练习&quot;">​</a></h2><h3 id="基础练习-必做" tabindex="-1">基础练习（必做） <a class="header-anchor" href="#基础练习-必做" aria-label="Permalink to &quot;基础练习（必做）&quot;">​</a></h3><p><strong>练习1</strong>：化简</p><ul><li>(1) sin(3π/2-α)</li><li>(2) cos(π+α)·sin(α-2π)</li></ul><p><strong>练习2</strong>：已知sinα = 3/5，α∈(π/2,π)，求cosα和tanα。</p><p><strong>练习3</strong>：函数y = 2sin(2x+π/3)的振幅、周期、初相分别是？</p><p><strong>练习4</strong>：在△ABC中，a=3, b=4, c=5，判断三角形形状并求最大角。</p><p><strong>参考答案</strong>：</p><ul><li>练习1：(1) -cosα；(2) -sinα·cosα</li><li>练习2：cosα = -4/5，tanα = -3/4</li><li>练习3：振幅2，周期π，初相π/3</li><li>练习4：直角三角形，最大角90°</li></ul><hr><h3 id="提高练习-选做" tabindex="-1">提高练习（选做） <a class="header-anchor" href="#提高练习-选做" aria-label="Permalink to &quot;提高练习（选做）&quot;">​</a></h3><p><strong>练习5</strong>：化简 (sin50°/sin20°) - (cos50°/cos20°)</p><p><strong>练习6</strong>：在△ABC中，acosA = bcosB，判断三角形形状。</p><hr><h2 id="五、faq常见问题" tabindex="-1">五、FAQ常见问题 <a class="header-anchor" href="#五、faq常见问题" aria-label="Permalink to &quot;五、FAQ常见问题&quot;">​</a></h2><h3 id="faq-1-诱导公式口诀记不住" tabindex="-1">FAQ 1：诱导公式口诀记不住 <a class="header-anchor" href="#faq-1-诱导公式口诀记不住" aria-label="Permalink to &quot;FAQ 1：诱导公式口诀记不住&quot;">​</a></h3><p><strong>记忆方法</strong>：</p><ul><li><strong>奇变偶不变</strong>：看π/2的系数，奇数变函数名，偶数不变</li><li><strong>符号看象限</strong>：把α当成锐角，看原函数在对应象限的符号</li></ul><p><strong>示例</strong>：sin(π+α)</p><ul><li>π是π/2的2倍（偶）→ sin不变</li><li>π+α在第三象限，sin为负</li><li>∴ sin(π+α) = -sinα</li></ul><hr><h3 id="faq-2-三角恒等变换时不知道选哪个公式" tabindex="-1">FAQ 2：三角恒等变换时不知道选哪个公式 <a class="header-anchor" href="#faq-2-三角恒等变换时不知道选哪个公式" aria-label="Permalink to &quot;FAQ 2：三角恒等变换时不知道选哪个公式&quot;">​</a></h3><p><strong>选择策略</strong>：</p><ol><li><strong>看角的关系</strong>：2α和α→用二倍角；α±β→用和差角</li><li><strong>看函数名统一</strong>：既有sin又有cos→考虑合一（辅助角公式）</li><li><strong>看次数</strong>：二次→用降幂公式降为一次</li></ol><p><strong>口诀</strong>：角优先，次优先，名统一</p><hr><h3 id="faq-3-解三角形时正弦余弦不知道用哪个" tabindex="-1">FAQ 3：解三角形时正弦余弦不知道用哪个 <a class="header-anchor" href="#faq-3-解三角形时正弦余弦不知道用哪个" aria-label="Permalink to &quot;FAQ 3：解三角形时正弦余弦不知道用哪个&quot;">​</a></h3><p><strong>选择依据</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">已知条件</th><th style="text-align:left;">选用定理</th></tr></thead><tbody><tr><td style="text-align:center;">两角一边</td><td style="text-align:left;">正弦定理</td></tr><tr><td style="text-align:center;">两边一对角</td><td style="text-align:left;">正弦定理（注意多解情况）</td></tr><tr><td style="text-align:center;">两边夹角</td><td style="text-align:left;">余弦定理</td></tr><tr><td style="text-align:center;">三边</td><td style="text-align:left;">余弦定理</td></tr></tbody></table><p><strong>记忆</strong>：</p><ul><li>有夹角→余弦</li><li>有对角→正弦</li><li>三边→余弦</li></ul><hr><h3 id="faq-4-三角函数图像变换顺序搞混" tabindex="-1">FAQ 4：三角函数图像变换顺序搞混 <a class="header-anchor" href="#faq-4-三角函数图像变换顺序搞混" aria-label="Permalink to &quot;FAQ 4：三角函数图像变换顺序搞混&quot;">​</a></h3><p><strong>变换顺序原则</strong>：</p><ul><li><strong>先伸缩（ω），后平移（φ）</strong></li><li>y = sinx → y = sin(ωx) → y = sin(ωx+φ)</li></ul><p><strong>注意</strong>：</p><ul><li>平移量是φ/ω，不是φ</li><li>例：y = sin(2x+π/3) = sin[2(x+π/6)]，向左平移π/6</li></ul><hr><h2 id="六、本章检查清单" tabindex="-1">六、本章检查清单 <a class="header-anchor" href="#六、本章检查清单" aria-label="Permalink to &quot;六、本章检查清单&quot;">​</a></h2><ul><li>[ ] 能熟练进行角度与弧度的换算</li><li>[ ] 能准确画出sinx, cosx, tanx的图像</li><li>[ ] 能根据y = Asin(ωx+φ)+B说出各参数意义</li><li>[ ] 熟练运用诱导公式化简</li><li>[ ] 熟练运用和差角、二倍角公式</li><li>[ ] 能正确选择正弦/余弦定理解三角形</li><li>[ ] 能求三角形面积</li></ul><hr><p><strong>文档编号</strong>: Math-Learn-Detail-002<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,135)])])}const u=a(t,[["render",o]]);export{d as __pageData,u as default};
